#!/bin/bash
# backup.sh - directory backup with retention
set -euo pipefail

BACKUP_DIR="/backups"
RETENTION_DAYS=7

usage() { echo "Usage: $0 [-d dir] [-r days] <source>"; exit 1; }

while getopts "d:r:h" opt; do
  case $opt in
    d) BACKUP_DIR="$OPTARG" ;;
    r) RETENTION_DAYS="$OPTARG" ;;
    h|?) usage ;;
  esac
done
shift $((OPTIND-1))

SOURCE="${1:?Source required}"
[ ! -d "$SOURCE" ] && echo "Error: not found" >&2 && exit 1

mkdir -p "$BACKUP_DIR"
NAME="backup-$(basename "$SOURCE")-$(date +%Y%m%d_%H%M%S).tar.gz"

tar -czf "$BACKUP_DIR/$NAME" "$SOURCE" && {
  echo "Created: $BACKUP_DIR/$NAME"
  find "$BACKUP_DIR" -name "*.tar.gz" -mtime +$RETENTION_DAYS -delete
  echo "Cleaned older than $RETENTION_DAYS days"
} || { echo "Backup failed" >&2; exit 1; }
